/*    _   __   ___    _   ____    _    _        _____    ___     _____     | | / /  / _ \  | | |  _ \  | |  | |      |___  |  / _ \   |  ___|     | |/ /  | |_| | | | | |_| | |  \/  |         / /  | |_| |  | |__     |   /   |  _  | | | |  _ /  | |\/| |        / /   |  _  |  |  __|     | |\ \  | | | | | | | | \ \ | |  | |       / /__  | | | |  | |     |_| \_\ |_| |_| |_| |_| |_| |_|  |_|      |_____| |_| |_|  |_|      */#include<bits/stdc++.h>using namespace std;typedef long long ll ;#ifndef ONLINE_JUDGE#include "debug.cpp"#else#define kar(...)#endif#define pb push_back#define F first#define S second#define all(x) x.begin(),x.end()#define rall(x) x.rbegin(),x.rend()#define endl '\n'#define int ll const ll N = 1e4+ 5 ,  MOD =1e9+7, mod=1e9+7, INF = 1e18+5; vector <int > graph[N]  ;int  n , m , k ,  a[N], sum , res ;multiset<int> ms ; int add (int x ){    if (x <=0) return -INF;    if (ms.size()<k){        ms.insert(x);        sum += x;        return INF;    }    int rass = *ms.begin();    if (x>=rass){        ms .insert(x);        sum += x ;        ms .erase (ms.find(rass));        sum -= rass ;        return rass ;    }    return -INF ;} void rmv (int x , int flag){    if (flag == -INF ) return;    ms.erase (ms.find(x)) ;    sum -= x;    if (flag == INF) return;    ms .insert(flag);    sum += flag ;} void dfs (int curr,int parent, int dist = 1){    if (dist >= m  ) return ;    for (auto child : graph[curr]){        if (child == parent) continue;        int d = add (a[child]);        res = max (res , sum);        dfs (child,curr, dist+1);        rmv (a[child], d);    }} void solve(){    cin >> n>> m >> k ;    int fin = 0 ;    for (int i= 1 ;i<= n;i++) cin >> a[i] ;    ms.clear();    for (int i= 1 ;i<= n;i++) graph[i].clear();    for (int i= 1 ; i<= n-1;i++){        int u , v ;        cin >> u>> v ;        graph[u] .pb(v);        graph[v] .pb(u);    }    for (int i= 1  ;i<= n;i++) {        sum = res = 0 ;        add (a[i]);        dfs (i,-1);        if (a[i]>0)rmv(a[i],INF);        fin = max (res , fin);    }    cout << fin << endl;} int32_t main(){    #ifndef ONLINE_JUDGE    freopen("input.txt","r",stdin);freopen("output.txt","w",stdout);    #endif    ios::sync_with_stdio(false);cin.tie(NULL);srand(time(0)); ll test_case=1;    cin >> test_case ;    while (test_case--)  solve() ;}